"""Render characterization/refactor views from atomic_manifest.json.

The JSON manifest is authoritative.  The generated Markdown files are
deterministic projections and must not be edited by hand.
"""

from __future__ import annotations

import json
from pathlib import Path
from typing import Any


ROOT = Path(__file__).resolve().parent
MANIFEST = ROOT / "atomic_manifest.json"
GENERATED_NOTE = (
    "<!-- Generated by render_phase_a_reports.py from atomic_manifest.json. "
    "Do not edit by hand. -->\n\n"
)


def _load() -> dict[str, Any]:
    return json.loads(MANIFEST.read_text(encoding="utf-8"))


def _cell(value: Any) -> str:
    if value is None:
        return "—"
    if isinstance(value, bool):
        return "yes" if value else "no"
    if isinstance(value, list):
        return "<br>".join(_cell(item) for item in value) if value else "—"
    if isinstance(value, dict):
        return "<br>".join(f"{key}: {_cell(item)}" for key, item in value.items())
    return str(value).replace("|", "\\|").replace("\n", " ")


def _write(name: str, title: str, body: list[str]) -> None:
    text = GENERATED_NOTE + f"# {title}\n\n" + "\n".join(body).rstrip() + "\n"
    (ROOT / name).write_text(text, encoding="utf-8")


def render_inventory(data: dict[str, Any]) -> None:
    current = data.get("current_refactor_execution", {})
    overrides = current.get("inventory_overrides", {})
    group_overrides = current.get("inventory_group_overrides", {})
    body = [
        "Authority: `atomic_manifest.json`. Paths are repository-relative.",
        "",
        "Historical selected-input rows are preserved in the manifest. Current "
        "combined-base source/validator identities below apply the explicit "
        "`current_refactor_execution.inventory_overrides` overlay.",
        "",
        "## Selected inputs",
        "",
        "| ID | Catalog/lifecycle | Role | Exact path | SHA-256 | Freshness | Demonstrated contribution | Unresolved |",
        "|---|---|---|---|---|---|---|---|",
    ]
    for item in data["selected_inputs"]:
        item = {**item, **overrides.get(item["id"], {})}
        body.append(
            "| "
            + " | ".join(
                _cell(item.get(key))
                for key in (
                    "id",
                    "catalog",
                    "role",
                    "path",
                    "sha256",
                    "freshness",
                    "gets_right",
                    "unresolved",
                )
            )
            + " |"
        )
    body.extend(
        [
            "",
            "Every selected input has `sidecar_sha256: null` and "
            "`image_hashes: []` unless explicitly listed in the manifest. "
            "The input landing selected no sidecars or images.",
            "",
            "## Group-resolved inventory fields",
            "",
            "Each selected ID inherits the row matching its prefix. This is the "
            "manifest's machine-readable resolution rule, not a second authority.",
            "",
            "| Prefix | Parameter ownership | Units/datums/transforms | Construction and hidden ancestry | Outputs and validators | Consumers | Confidence / uncertainty |",
            "|---|---|---|---|---|---|---|",
        ]
    )
    for prefix, group in data["inventory_groups"].items():
        group = {**group, **group_overrides.get(prefix, {})}
        body.append(
            f"| {prefix}. | {_cell(group['parameter_ownership'])} | "
            f"{_cell(group['units_datums_axes_transforms'])} | "
            f"{_cell(group['construction_and_boolean_stages'])}<br>"
            f"{_cell(group['import_ancestry_hidden_mutation'])} | "
            f"{_cell(group['outputs'])}<br>{_cell(group['validators'])} | "
            f"{_cell(group['downstream_consumers'])} | "
            f"{_cell(group['confidence_uncertainty'])} |"
        )
    body.extend(
        [
            "",
            "## Historical Phase A source ancestry snapshot",
            "",
            "These 19 rows preserve the initial characterization snapshot. The "
            "current exact producer dependency set, including every loaded "
            "path/revision/hash, is `variant-r-producer-source-closure.json`; "
            "the final release identity is in `final-acceptance-evidence.json`.",
            "",
            "| Order | Path | SHA-256 | Responsibility / mutation |",
            "|---:|---|---|---|",
        ]
    )
    for index, item in enumerate(data["source_ancestry"], 1):
        body.append(
            f"| {index} | {_cell(item['path'])} | {_cell(item['sha256'])} | "
            f"{_cell(item['responsibility'])} |"
        )
    body.extend(
        [
            "",
            "## Coordinate and construction contract",
            "",
            f"- {_cell(data['coordinate_contract'])}",
            "",
            "- Construction stages: "
            + _cell(
                current.get(
                    "construction_stages_override",
                    data["construction_stages"],
                )
            ),
            "",
            "- Output/validation boundary: "
            + _cell(
                current.get(
                    "output_validation_boundary_override",
                    data["output_validation_boundary"],
                )
            ),
        ]
    )
    _write("inventory.md", "Authoritative input inventory", body)


def render_atoms(data: dict[str, Any]) -> None:
    current = data.get("current_refactor_execution")
    overrides = (
        current.get("atom_overrides", {})
        if current
        else {}
    )
    body = [
        "Authority: `atomic_manifest.json`.",
        *(
            [
                "",
                f"Current execution overlay: **{_cell(current['status'])}**. "
                "Rows retain historical characterization; the overlay supersedes "
                "old operational blocker wording.",
            ]
            if current
            else []
        ),
        "",
        "| Semantic ID | Owner | Current owner/source | Dependencies | Mates | Baseline | Shareability | Readiness | Conflicts |",
        "|---|---|---|---|---|---|---|---|---|",
    ]
    for atom in data["atoms"]:
        atom = {**atom, **overrides.get(atom["id"], {})}
        body.append(
            "| "
            + " | ".join(
                _cell(atom.get(key))
                for key in (
                    "id",
                    "owner",
                    "owning_source",
                    "dependencies",
                    "mating_atoms",
                    "reproducible_baseline",
                    "shareability",
                    "readiness",
                    "conflicts",
                )
            )
            + " |"
        )
    body.extend(
        [
            "",
            "Protected invariants, tolerances, print implications, consumers, "
            "and candidate references remain in the manifest to keep this view compact.",
        ]
    )
    _write("atomic_map.md", "Atomic ownership map", body)


def render_compatibility(data: dict[str, Any]) -> None:
    current = data.get("current_refactor_execution")
    overrides = (
        current.get("atom_overrides", {})
        if current
        else {}
    )
    body = [
        "Authority: the `compatibility_class` and `comparison` fields for each "
        "atom in `atomic_manifest.json`.",
        *(
            [
                "",
                f"Current execution overlay: **{_cell(current['status'])}**. "
                "Historical source-readiness statements remain provenance, not "
                "the current geometry gate.",
            ]
            if current
            else []
        ),
        "",
        "| Atom | Classification | Variant comparison | Later-synthesis blocker |",
        "|---|---|---|---|",
    ]
    for atom in data["atoms"]:
        atom = {**atom, **overrides.get(atom["id"], {})}
        body.append(
            f"| {_cell(atom['id'])} | {_cell(atom['compatibility_class'])} | "
            f"{_cell(atom['comparison'])} | {_cell(atom.get('synthesis_blocker'))} |"
        )
    _write("compatibility_matrix.md", "Family/variant compatibility matrix", body)


def render_dependencies(data: dict[str, Any]) -> None:
    body = [
        "Authority: atom dependency and consumer fields in `atomic_manifest.json`.",
        "",
        "```mermaid",
        "flowchart LR",
    ]
    ids = {atom["id"] for atom in data["atoms"]}
    for atom in data["atoms"]:
        label = atom["id"].replace('"', "'")
        body.append(f'  {atom["id"].replace(".", "_")}["{label}"]')
    for atom in data["atoms"]:
        target = atom["id"].replace(".", "_")
        for dependency in atom["dependencies"]:
            if dependency in ids:
                body.append(f"  {dependency.replace('.', '_')} --> {target}")
    body.extend(
        [
            "```",
            "",
            "Deferred external components terminate at interface atoms; no acoustic "
            "or product geometry is integrated by this map.",
        ]
    )
    _write("dependency_graph.md", "Dependency graph", body)


def render_baseline(data: dict[str, Any]) -> None:
    baseline = data["baseline"]
    current = data.get("current_refactor_execution")
    body = [
        *(
            [
                f"Current checkpoint status: **{_cell(current['status'])}**.",
                "",
                "## Current combined-base reproduction",
                "",
                f"- Exact base: `{current['exact_base']}`",
                f"- Current source: `{current['current_source']['path']}`",
                f"- Source SHA-256: `{current['current_source']['sha256']}`",
                f"- Generation job: `{current['generation']['job_id']}`; "
                f"{current['generation']['elapsed_seconds']} s; "
                f"{current['generation']['peak_rss_bytes']} bytes peak RSS",
                f"- Equivalence job: `{current['equivalence']['job_id']}`; "
                f"{current['equivalence']['elapsed_seconds']} s; "
                f"{current['equivalence']['peak_rss_bytes']} bytes peak RSS",
                f"- Full parts/protected sections: "
                f"{current['equivalence']['full_parts_and_protected_sections']}; "
                f"all equivalent: {_cell(current['equivalence']['all_equivalent'])}",
                f"- Maximum removed/added material: "
                f"{current['equivalence']['max_removed_material_mm3']} / "
                f"{current['equivalence']['max_added_material_mm3']} mm³",
                f"- Bucket/baffle overlap: "
                f"{current['equivalence']['bucket_baffle_overlap_mm3']} mm³",
                f"- STEP round-trip: {current['equivalence']['step_round_trip']}",
                "",
                current["protected_imperfection"],
                "",
                "## Historical Phase A / early Phase B baseline record",
                "",
            ]
            if current
            else []
        ),
        f"Historical checkpoint status: **{_cell(baseline['status'])}**.",
        "",
        "## Native source reproduction",
        "",
        f"- Owning source: `{baseline['source_path']}`",
        f"- Source SHA-256: `{baseline['source_sha256']}`",
        f"- CAD job: `{baseline['job_id']}`",
        f"- Outcome: {_cell(baseline['outcome'])}",
        f"- Exact failure: `{baseline['failure']}`",
        f"- Elapsed / peak RSS: {baseline['elapsed_seconds']} s / "
        f"{baseline['peak_rss_bytes']} bytes",
        f"- Published outputs: {_cell(baseline['published_outputs'])}",
        f"- Validator: {_cell(baseline['validator_status'])}",
        "",
        "This is a source-boundary failure. The immutable STEP references remain "
        "evidence; none is promoted to Python authority.",
        "",
        "## Immutable reference measurements",
        "",
        "| Input ID | Solids | Valid | Volume (mm³) | Bounds size X×Y×Z (mm) | Center of mass X,Y,Z (mm) | Faces / edges / vertices | Interpretation |",
        "|---|---:|---|---:|---|---|---|---|",
    ]
    for item in baseline["reference_measurements"]:
        body.append(
            f"| {_cell(item['input_id'])} | {_cell(item['solid_count'])} | "
            f"{_cell(item['valid'])} | {_cell(item['volume_mm3'])} | "
            f"{_cell(item['bbox_size_mm'])} | "
            f"{_cell(item['center_of_mass_mm'])} | "
            f"{item['faces']} / {item['edges']} / {item['vertices']} | "
            f"{_cell(item['interpretation'])} |"
        )
    body.extend(
        [
            "",
            "## Evidence binding",
            "",
            f"- Review copy STEP: `{baseline['review_evidence']['step_path']}`",
            f"- STEP SHA-256: `{baseline['review_evidence']['step_sha256']}`",
            f"- Sidecar SHA-256: `{baseline['review_evidence']['sidecar_sha256']}`",
            f"- Snapshot job specification: `{baseline['review_evidence']['snapshot_job']}`",
            f"- Snapshot outputs: {_cell(baseline['review_evidence']['snapshot_outputs'])}",
            f"- Viewer record: `{baseline['review_evidence']['viewer_record']}`",
            "",
            "A matching bounding box is not treated as equivalence. The sentence "
            "above is the preserved historical record; the current combined-base "
            "overlay at the top supplies the accepted semantic and STEP round-trip "
            "proof.",
        ]
    )
    _write("baseline_report.md", "Reproducible baseline report", body)


def render_printability(data: dict[str, Any]) -> None:
    body = [
        "Authority: `print_contracts` in `atomic_manifest.json`. These are "
        "characterization records, not geometry changes.",
        "",
        "| Part/variant | Intended bed contact | Build direction in design coordinates | Seating/adhesion evidence | Current risks | Later work |",
        "|---|---|---|---|---|---|",
    ]
    for item in data["print_contracts"]:
        body.append(
            "| "
            + " | ".join(
                _cell(item.get(key))
                for key in (
                    "id",
                    "bed_contact",
                    "build_direction",
                    "seating_and_adhesion",
                    "risks",
                    "later_work",
                )
            )
            + " |"
        )
    body.extend(
        [
            "",
            "Physical-print behavior remains uncertain until slicer and printed-part "
            "evidence exist. No support, brace, seam, or hatch geometry was corrected.",
        ]
    )
    _write("printability_report.md", "Printability characterization", body)


def render_pilot(data: dict[str, Any]) -> None:
    pilot = data["phase_b_pilot"]
    native = pilot["native_boundary_comparison"]
    artifacts = pilot["artifact_comparison"]
    visual = pilot["visual_comparison"]
    body = [
        f"Status: **{pilot['status']}**",
        "",
        f"Atom: `{pilot['atom_id']}`",
        "",
        "## Source change and module boundary",
        "",
        f"- Exact owner: `{pilot['exact_owner']}`",
        f"- Boundary: {pilot['module_boundary']}",
        *[f"- {item}" for item in pilot["source_change"]],
        "",
        "## Exact preserved contract",
        "",
        f"- Units: `{pilot['preserved_parameters']['units']}`",
        f"- Envelope: `{pilot['preserved_parameters']['envelope_mm']}` mm",
        f"- Center: `{pilot['preserved_parameters']['center_xyz_mm']}` mm",
        f"- Named planes: `{pilot['preserved_parameters']['named_planes_mm']}`",
        f"- Axis directions: `{pilot['preserved_parameters']['directions']}`",
        f"- Tolerance: `{pilot['preserved_parameters']['tolerance']}` mm",
        "",
        "## Native-free evidence",
        "",
        f"- Fast contract: `{pilot['fast_contract']['status']}`; "
        f"{pilot['fast_contract']['selected_requirements']} selected requirements; "
        f"{pilot['fast_contract']['elapsed_seconds']} s; "
        f"{pilot['fast_contract']['peak_rss_bytes']} bytes peak RSS.",
        f"- Lightweight suite: `{pilot['lightweight_checks']['status']}`; "
        f"{pilot['lightweight_checks']['tests']} tests and "
        f"{pilot['lightweight_checks']['subtests']} subtests; "
        f"{pilot['lightweight_checks']['elapsed_seconds']} s; "
        f"{pilot['lightweight_checks']['peak_rss_bytes']} bytes peak RSS.",
        "",
        "## Native boundary comparison",
        "",
        "| State | Job | Elapsed (s) | Peak RSS (bytes) | Outputs | Result |",
        "|---|---|---:|---:|---:|---|",
        f"| Before | `{native['before']['job_id']}` | "
        f"{native['before']['elapsed_seconds']} | "
        f"{native['before']['peak_rss_bytes']} | "
        f"{native['before']['outputs']} | `{native['before']['failure']}` |",
        f"| After | `{native['after']['job_id']}` | "
        f"{native['after']['elapsed_seconds']} | "
        f"{native['after']['peak_rss_bytes']} | "
        f"{native['after']['outputs']} | `{native['after']['failure']}` |",
        "",
        native["interpretation"],
        "",
        "## Artifact and visual comparison",
        "",
        f"- Before STEP SHA-256: `{artifacts['before_step_sha256']}`",
        f"- After STEP SHA-256: `{artifacts['after_step_sha256']}`",
        f"- After-artifact boundary: {artifacts['after_step_reason']}",
        f"- Before visual: {visual['before']}",
        f"- After visual: {visual['after']}",
        f"- Claim boundary: {visual['claim']}",
        "",
        "## Architectural lessons",
        "",
        *[f"- {item}" for item in pilot["architectural_lessons"]],
    ]
    _write("pilot_report.md", "Phase B first-atom checkpoint", body)


def main() -> int:
    data = _load()
    render_inventory(data)
    render_atoms(data)
    render_compatibility(data)
    render_dependencies(data)
    render_baseline(data)
    render_printability(data)
    if "phase_b_pilot" in data:
        render_pilot(data)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
